import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [requests, setRequests] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const [editingProject, setEditingProject] = useState(null); 
  const adminPassword = "admin123";

  const fetchData = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
    } catch (err) { console.error("Error fetching data:", err); }
  };

  useEffect(() => { if (isLoggedIn) fetchData(); }, [isLoggedIn]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === adminPassword) setIsLoggedIn(true);
    else alert("Incorrect Password!");
  };

  // --- १. डेटा अपडेट लॉजिक (नंबर पक्का करने के लिए) ---
  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      const payload = {
        ...editingProject,
        totalBudget: Number(editingProject.totalBudget) || 0,
        advancePaid: Number(editingProject.advancePaid) || 0,
        progress: Number(editingProject.progress) || 0
      };
      await axios.put(`http://localhost:5000/api/update-status/${editingProject._id}`, payload);
      alert("✅ Project Updated Successfully!");
      setEditingProject(null);
      fetchData();
    } catch (err) { alert("❌ Update failed!"); }
  };

  // --- २. क्विक फुल पेड लॉजिक ---
  const handleQuickFullPaid = async (req) => {
    if (window.confirm(`Mark ${req.fullName} as Fully Paid?`)) {
      try {
        await axios.put(`http://localhost:5000/api/update-status/${req._id}`, {
          ...req,
          advancePaid: Number(req.totalBudget) || 0,
          paymentStatus: "Paid"
        });
        fetchData();
      } catch (err) { alert("❌ Operation failed!"); }
    }
  };

  const handleResolveRevision = async (id) => {
    if (window.confirm("Mark as completed?")) {
      try {
        await axios.put(`http://localhost:5000/api/update-status/${id}`, { revisionsRequested: "" });
        fetchData();
      } catch (err) { alert("❌ Error!"); }
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Delete project?")) {
      try {
        await axios.delete(`http://localhost:5000/api/delete-request/${id}`);
        fetchData();
      } catch (err) { alert("Delete failed!"); }
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="d-flex justify-content-center align-items-center bg-light" style={{minHeight: '100vh'}}>
        <div className="card shadow border-0 p-4" style={{width: '350px'}}>
          <h4 className="text-center fw-bold mb-4">Admin Access</h4>
          <form onSubmit={handleLogin}>
            <input type="password" placeholder="Password" className="form-control mb-3 text-center" value={password} onChange={(e) => setPassword(e.target.value)} required />
            <button className="btn btn-dark w-100 fw-bold shadow">Login</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="container-fluid py-4 px-lg-5 bg-light" style={{minHeight: '100vh'}}>
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="fw-bold m-0 text-dark">Project Manager</h2>
        <button className="btn btn-danger btn-sm px-4 rounded-pill" onClick={() => setIsLoggedIn(false)}>Logout</button>
      </div>

      <div className="card border-0 shadow-sm rounded-4 overflow-hidden">
        <table className="table table-hover mb-0 align-middle">
          <thead className="bg-dark text-white">
            <tr className="small text-uppercase">
              <th className="py-3 ps-4">Client</th>
              <th>Progress</th>
              <th>Financials</th>
              <th>Revision</th>
              <th>Status</th>
              <th className="text-end pe-4">Actions</th>
            </tr>
          </thead>
          <tbody>
            {requests.map((req) => {
              // --- ३. यहाँ हो रही है असली कैलकुलेशन (Force Number) ---
              const budget = Number(req.totalBudget) || 0;
              const paid = Number(req.advancePaid) || 0;
              const remaining = budget - paid;

              return (
                <tr key={req._id}>
                  <td className="ps-4">
                    <div className="fw-bold">{req.fullName}</div>
                    <small className="text-primary">{req.serviceType}</small>
                  </td>
                  <td>
                    <div className="progress" style={{height: '6px', width: '80px'}}>
                      <div className="progress-bar bg-success" style={{width: `${req.progress}%`}}></div>
                    </div>
                    <small className="fw-bold">{req.progress}%</small>
                  </td>
                  <td>
                    <div className="small">
                      Budget: <b>₹{budget}</b> <br/>
                      Paid: <b className="text-success">₹{paid}</b> <br/>
                      {/* अगर पैसे बाकी हैं तो लाल रंग में दिखाएगा */}
                      {remaining > 0 ? (
                        <div className="mt-1 border-top pt-1">
                           Rem: <b className="text-danger">₹{remaining}</b>
                        </div>
                      ) : budget > 0 ? (
                        <span className="badge bg-success-subtle text-success mt-1">Settled</span>
                      ) : null}
                    </div>
                    {/* बटन तभी आएगा जब पैसे वाकई बाकी हों */}
                    {remaining > 0 && budget > 0 && (
                      <button className="btn btn-outline-success btn-xs mt-1 py-0 px-2 fw-bold" style={{fontSize: '9px'}} onClick={() => handleQuickFullPaid(req)}>Mark Paid</button>
                    )}
                  </td>
                  <td>
                    {req.revisionsRequested ? (
                      <div className="bg-warning-subtle p-1 border border-warning rounded" style={{maxWidth: '150px'}}>
                        <small className="d-block mb-1 text-truncate">{req.revisionsRequested}</small>
                        <button className="btn btn-success btn-xs w-100 py-0" style={{fontSize: '9px'}} onClick={() => handleResolveRevision(req._id)}>DONE</button>
                      </div>
                    ) : <small className="text-muted">None</small>}
                  </td>
                  <td>
                    <span className={`badge rounded-pill ${req.status === 'Completed' ? 'bg-success' : 'bg-warning text-dark'}`}>
                      {req.status}
                    </span>
                  </td>
                  <td className="text-end pe-4">
                    <button className="btn btn-sm btn-light border me-1" onClick={() => setEditingProject(req)}>Edit</button>
                    <button className="btn btn-sm btn-outline-danger" onClick={() => handleDelete(req._id)}>Delete</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* --- EDIT MODAL --- */}
      {editingProject && (
        <div className="modal show d-block" style={{backgroundColor: 'rgba(0,0,0,0.6)'}}>
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content border-0 rounded-4">
              <div className="modal-header border-0 bg-light">
                <h5 className="fw-bold m-0">Quick Edit</h5>
                <button type="button" className="btn-close" onClick={() => setEditingProject(null)}></button>
              </div>
              <form onSubmit={handleUpdate}>
                <div className="modal-body">
                  <div className="row g-3">
                    <div className="col-6">
                      <label className="small fw-bold">Budget</label>
                      <input type="number" className="form-control" value={editingProject.totalBudget} onChange={(e) => setEditingProject({...editingProject, totalBudget: e.target.value})} />
                    </div>
                    <div className="col-6">
                      <label className="small fw-bold">Paid</label>
                      <input type="number" className="form-control" value={editingProject.advancePaid} onChange={(e) => setEditingProject({...editingProject, advancePaid: e.target.value})} />
                    </div>
                    <div className="col-12">
                      <label className="small fw-bold">Status</label>
                      <select className="form-select" value={editingProject.status} onChange={(e) => setEditingProject({...editingProject, status: e.target.value})}>
                        <option value="Pending">Pending</option>
                        <option value="In Progress">In Progress</option>
                        <option value="Completed">Completed</option>
                      </select>
                    </div>
                  </div>
                </div>
                <div className="modal-footer border-0">
                  <button type="submit" className="btn btn-dark w-100 fw-bold shadow">Save All Changes</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default Admin;
